// src/pages/ProfilePage.js - Updated with proper enrollment handling
import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { useSensor } from '../hooks/useSensor';
import authService from '../services/authService';
import './ProfilePage.css';

const ProfilePage = () => {
    const { user, logout } = useAuth();
    const { status: sensorStatus, connect, disconnect, enrollFingerprint } = useSensor();
    
    const [activeTab, setActiveTab] = useState('profile');
    const [profile, setProfile] = useState({
        username: user?.username || '',
        email: user?.email || '',
        healthRecordId: user?.healthRecordId || ''
    });
    
    const [passwords, setPasswords] = useState({
        current: '',
        new: '',
        confirm: ''
    });
    
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });
    const [fingerprintStatus, setFingerprintStatus] = useState('not_enrolled');
    const [isConnecting, setIsConnecting] = useState(false);
    
    // Enrollment UI state
    const [showEnrollmentModal, setShowEnrollmentModal] = useState(false);
    const [enrollmentStep, setEnrollmentStep] = useState(0);
    const [enrollmentMessage, setEnrollmentMessage] = useState('');
    const [enrollmentInstruction, setEnrollmentInstruction] = useState('');
    const [enrollmentIcon, setEnrollmentIcon] = useState('👆');
    const [enrollmentColor, setEnrollmentColor] = useState('#3B82F6');
    const [isEnrolling, setIsEnrolling] = useState(false);

    const loadProfile = useCallback(async () => {
        try {
            const data = await authService.getProfile();
            setProfile({
                username: data.user?.username || user?.username || '',
                email: data.user?.email || user?.email || '',
                healthRecordId: data.user?.health_record_id || user?.healthRecordId || ''
            });
            // Check if fingerprint is enrolled from the response
            const hasFingerprint = data.fingerprintEnrolled === true;
            setFingerprintStatus(hasFingerprint ? 'enrolled' : 'not_enrolled');
            console.log('Profile loaded, fingerprint enrolled:', hasFingerprint);
        } catch (error) {
            console.error('Failed to load profile:', error);
            showMessage('error', 'Failed to load profile');
        }
    }, [user]);

    useEffect(() => {
        loadProfile();
    }, [loadProfile]);

    // Listen for enrollment steps from sensor
    useEffect(() => {
        if (!window.webSerialService) return;
        
        const handleEnrollStep = (stepData) => {
            console.log('Enrollment step received:', stepData);
            setEnrollmentStep(stepData.step);
            setEnrollmentMessage(stepData.message);
            setEnrollmentInstruction(stepData.instruction);
            setEnrollmentIcon(stepData.icon);
            setEnrollmentColor(stepData.color);
            
            if (stepData.success) {
                console.log('Enrollment successful! Refreshing profile...');
                // Refresh profile to update fingerprint status
                setTimeout(async () => {
                    await loadProfile(); // Reload profile to get updated fingerprint status
                    setShowEnrollmentModal(false);
                    setIsEnrolling(false);
                    setEnrollmentStep(0);
                    showMessage('success', stepData.message);
                }, 2000);
            }
            
            if (stepData.error) {
                setTimeout(() => {
                    setIsEnrolling(false);
                    setEnrollmentStep(0);
                    showMessage('error', stepData.message);
                }, 3000);
            }
        };
        
        window.webSerialService.on('enroll-step', handleEnrollStep);
        
        return () => {
            window.webSerialService.off('enroll-step', handleEnrollStep);
        };
    }, [loadProfile]);

    const showMessage = (type, text) => {
        setMessage({ type, text });
        setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    };

    const handleConnectSensor = useCallback(async () => {
        setIsConnecting(true);
        const result = await connect();
        if (result.success) {
            localStorage.setItem('sensorConnected', 'true');
            showMessage('success', 'Fingerprint sensor connected!');
        } else {
            showMessage('error', `Connection failed: ${result.error}`);
        }
        setIsConnecting(false);
    }, [connect]);

    const handleDisconnectSensor = useCallback(() => {
        disconnect();
        localStorage.removeItem('sensorConnected');
        showMessage('info', 'Sensor disconnected');
    }, [disconnect]);

    useEffect(() => {
        const wasConnected = localStorage.getItem('sensorConnected') === 'true';
        if (wasConnected && !sensorStatus.connected) {
            handleConnectSensor();
        }
    }, [sensorStatus.connected, handleConnectSensor]);

    const handleProfileUpdate = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const response = await authService.updateProfile({
                email: profile.email
            });
            if (response.success) {
                showMessage('success', 'Profile updated successfully');
            }
        } catch (error) {
            showMessage('error', error.message);
        } finally {
            setLoading(false);
        }
    };

    const handlePasswordChange = async (e) => {
        e.preventDefault();
        
        if (passwords.new !== passwords.confirm) {
            showMessage('error', 'New passwords do not match');
            return;
        }
        
        if (passwords.new.length < 6) {
            showMessage('error', 'Password must be at least 6 characters');
            return;
        }
        
        setLoading(true);
        try {
            const response = await authService.changePassword(passwords.current, passwords.new);
            if (response.success) {
                showMessage('success', 'Password changed successfully');
                setPasswords({ current: '', new: '', confirm: '' });
            }
        } catch (error) {
            showMessage('error', error.message);
        } finally {
            setLoading(false);
        }
    };

    const handleEnrollFingerprint = async () => {
        if (!sensorStatus.connected) {
            showMessage('error', 'Please connect the fingerprint sensor first');
            return;
        }
        
        setIsEnrolling(true);
        setShowEnrollmentModal(true);
        setEnrollmentStep(0);
        
        try {
            const result = await enrollFingerprint();
            console.log('Enrollment result:', result);
            // The success will be handled by the enroll-step event listener
        } catch (error) {
            setShowEnrollmentModal(false);
            setIsEnrolling(false);
            showMessage('error', error.message);
        }
    };

    const EnrollmentModal = () => (
        <div className="enrollment-modal-overlay">
            <div className="enrollment-modal">
                <div className="enrollment-header">
                    <h2>Fingerprint Enrollment</h2>
                    <button 
                        className="close-btn"
                        onClick={() => {
                            setShowEnrollmentModal(false);
                            setIsEnrolling(false);
                            setEnrollmentStep(0);
                        }}
                    >
                        ×
                    </button>
                </div>
                
                <div className="enrollment-content">
                    {/* Step Indicator */}
                    {enrollmentStep > 0 && enrollmentStep < 4 && (
                        <div className="step-indicator">
                            <div className="step-progress">
                                <div 
                                    className="step-progress-bar"
                                    style={{ width: `${(enrollmentStep / 3) * 100}%` }}
                                />
                            </div>
                            <div className="step-text">
                                Step {enrollmentStep} of 3
                            </div>
                        </div>
                    )}
                    
                    {/* Instruction Card */}
                    <div 
                        className="enrollment-instruction"
                        style={{ borderColor: enrollmentColor }}
                    >
                        <div className="enrollment-icon" style={{ fontSize: '64px' }}>
                            {enrollmentIcon}
                        </div>
                        <h3 style={{ color: enrollmentColor }}>
                            {enrollmentMessage || 'Ready to Enroll'}
                        </h3>
                        <p>{enrollmentInstruction || 'Click Start to begin fingerprint enrollment'}</p>
                    </div>
                    
                    {/* Tips */}
                    {enrollmentStep === 0 && (
                        <div className="enrollment-tips">
                            <h4>💡 Tips for successful enrollment:</h4>
                            <ul>
                                <li>Clean the sensor surface with a soft cloth</li>
                                <li>Make sure your finger is clean and dry</li>
                                <li>Place your finger gently but firmly on the sensor</li>
                                <li>Keep your finger steady during scanning</li>
                                <li>Use the same finger and position for both scans</li>
                            </ul>
                        </div>
                    )}
                    
                    {/* Waiting Animation */}
                    {enrollmentStep > 0 && enrollmentStep < 4 && (
                        <div className="waiting-animation">
                            <div className="pulse-ring"></div>
                            <div className="pulse-ring-delayed"></div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );

    return (
        <div className="profile-page">
            <div className="profile-header">
                <h1>Profile Settings</h1>
                <button onClick={logout} className="btn btn-secondary">
                    Logout
                </button>
            </div>

            {message.text && (
                <div className={`message ${message.type}`}>
                    {message.text}
                </div>
            )}

            {/* Enrollment Modal */}
            {showEnrollmentModal && <EnrollmentModal />}

            <div className="profile-tabs">
                <button 
                    className={`tab ${activeTab === 'profile' ? 'active' : ''}`}
                    onClick={() => setActiveTab('profile')}
                >
                    Profile Info
                </button>
                <button 
                    className={`tab ${activeTab === 'security' ? 'active' : ''}`}
                    onClick={() => setActiveTab('security')}
                >
                    Security
                </button>
                <button 
                    className={`tab ${activeTab === 'fingerprint' ? 'active' : ''}`}
                    onClick={() => setActiveTab('fingerprint')}
                >
                    Fingerprint
                </button>
            </div>

            <div className="profile-content">
                {activeTab === 'profile' && (
                    <div className="profile-info">
                        <h2>Profile Information</h2>
                        <form onSubmit={handleProfileUpdate}>
                            <div className="form-group">
                                <label>Username</label>
                                <input 
                                    type="text" 
                                    value={profile.username || ''}
                                    disabled
                                    className="readonly"
                                />
                                <small>Username cannot be changed</small>
                            </div>

                            <div className="form-group">
                                <label>Email</label>
                                <input 
                                    type="email" 
                                    value={profile.email || ''}
                                    onChange={(e) => setProfile({...profile, email: e.target.value})}
                                    placeholder="Enter your email"
                                />
                            </div>

                            <div className="form-group">
                                <label>Health Record ID</label>
                                <input 
                                    type="text" 
                                    value={profile.healthRecordId || ''}
                                    disabled
                                    className="readonly"
                                />
                                <small>Your unique health record identifier</small>
                            </div>

                            <button 
                                type="submit" 
                                className="btn btn-primary"
                                disabled={loading}
                            >
                                {loading ? 'Saving...' : 'Save Changes'}
                            </button>
                        </form>
                    </div>
                )}

                {activeTab === 'security' && (
                    <div className="security-settings">
                        <h2>Change Password</h2>
                        <form onSubmit={handlePasswordChange}>
                            <div className="form-group">
                                <label>Current Password</label>
                                <input 
                                    type="password" 
                                    value={passwords.current}
                                    onChange={(e) => setPasswords({...passwords, current: e.target.value})}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>New Password</label>
                                <input 
                                    type="password" 
                                    value={passwords.new}
                                    onChange={(e) => setPasswords({...passwords, new: e.target.value})}
                                    required
                                    minLength="6"
                                />
                            </div>

                            <div className="form-group">
                                <label>Confirm New Password</label>
                                <input 
                                    type="password" 
                                    value={passwords.confirm}
                                    onChange={(e) => setPasswords({...passwords, confirm: e.target.value})}
                                    required
                                />
                            </div>

                            <button 
                                type="submit" 
                                className="btn btn-primary"
                                disabled={loading}
                            >
                                {loading ? 'Changing...' : 'Change Password'}
                            </button>
                        </form>
                    </div>
                )}

                {activeTab === 'fingerprint' && (
                    <div className="fingerprint-settings">
                        <h2>Fingerprint Authentication</h2>
                        
                        {/* Sensor Connection Section */}
                        <div className="sensor-connection-section">
                            {!sensorStatus.connected ? (
                                <button 
                                    className="btn-connect-sensor"
                                    onClick={handleConnectSensor}
                                    disabled={isConnecting}
                                >
                                    {isConnecting ? 'Connecting...' : '🔌 Connect USB Fingerprint Sensor'}
                                </button>
                            ) : (
                                <div className="sensor-connected">
                                    <span className="sensor-status-connected">✅ USB Sensor Connected</span>
                                    <button 
                                        className="btn-disconnect-sensor"
                                        onClick={handleDisconnectSensor}
                                    >
                                        Disconnect
                                    </button>
                                </div>
                            )}
                        </div>

                        <div className="fingerprint-status">
                            <div className={`status-indicator ${fingerprintStatus}`}></div>
                            <div>
                                <h3>Status: {
                                    fingerprintStatus === 'enrolled' 
                                        ? '✅ Fingerprint Enrolled' 
                                        : '❌ Not Enrolled'
                                }</h3>
                                <p>
                                    {fingerprintStatus === 'enrolled' 
                                        ? 'You can use your fingerprint to log in'
                                        : 'Enroll your fingerprint for faster, more secure login'}
                                </p>
                            </div>
                        </div>

                        {sensorStatus.connected ? (
                            fingerprintStatus === 'enrolled' ? (
                                <button 
                                    className="btn btn-secondary"
                                    onClick={handleEnrollFingerprint}
                                    disabled={loading || isEnrolling}
                                >
                                    {isEnrolling ? 'Enrolling...' : 'Re-enroll Fingerprint'}
                                </button>
                            ) : (
                                <button 
                                    className="btn btn-primary"
                                    onClick={handleEnrollFingerprint}
                                    disabled={loading || isEnrolling}
                                >
                                    {isEnrolling ? 'Starting Enrollment...' : 'Enroll Fingerprint'}
                                </button>
                            )
                        ) : (
                            <div className="sensor-warning">
                                ⚠️ Fingerprint sensor not connected. 
                                Click "Connect USB Fingerprint Sensor" to begin enrollment.
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default ProfilePage;
